  mainContent: { flex: 1, marginLeft: '250px', marginTop: '60px', padding: '20px' },
  contentWrapper: { maxWidth: '1200px', margin: '0 auto' },
  pageTitle: { marginBottom: '24px', fontWeight: '700', fontSize: '28px', color: '#1a1a2e' },
  cardsRow: { display: 'flex', gap: '20px', flexWrap: 'wrap', marginBottom: '24px' },
  card: { flex: '1 1 220px', background: '#fff', borderRadius: '16px', boxShadow: '0 4px 20px rgba(0,0,0,0.08)', padding: '20px', display: 'flex', alignItems: 'center', gap: '16px', minWidth: '200px', transition: 'transform 0.2s, box-shadow 0.2s', cursor: 'pointer' },
  cardIconBg: { width: '56px', height: '56px', borderRadius: '12px', backgroundColor: '#e8effc', display: 'flex', alignItems: 'center', justifyContent: 'center' },
  cardIcon: { width: '28px', height: '28px' },
  cardContent: { flex: 1 },
  cardValue: { fontSize: '28px', fontWeight: '700', color: '#2846e3', lineHeight: 1.2 },
  cardTitle: { fontSize: '13px', color: '#666', marginTop: '4px', fontWeight: '600' },
  earningsCard: {},
  
  // Professional Statistics Section
  statisticsSection: { 
    background: '#fff', 
    borderRadius: '16px', 
    boxShadow: '0 4px 20px rgba(0,0,0,0.08)', 
    padding: '28px', 
    marginBottom: '24px',
    border: '1px solid #f0f0f0'
  },
  statisticsHeader: { 
    display: 'flex', 
    justifyContent: 'space-between', 
    alignItems: 'flex-start',
    marginBottom: '28px',
    flexWrap: 'wrap',
    gap: '16px'
  },
  statisticsTitle: { 
    margin: 0, 
    fontSize: '22px', 
    fontWeight: '700', 
    color: '#1a1a2e',
    marginBottom: '4px'
  },
  statisticsSubtitle: { 
    margin: 0, 
    fontSize: '13px', 
    color: '#999',
    fontWeight: '500'
  },
  chartControls: { 
    display: 'flex', 
    gap: '10px' 
  },
  controlBtn: { 
    padding: '10px 18px', 
    borderRadius: '8px', 
    border: '1px solid #e0e0e0', 
    background: '#f8f9fa', 
    color: '#666', 
    fontWeight: '600', 
    cursor: 'pointer', 
    fontFamily: 'Inria Serif, serif',
    transition: 'all 0.2s ease',
    fontSize: '13px'
  },
  controlBtnActive: { 
    background: 'linear-gradient(135deg, #3b82f6 0%, #1e40af 100%)', 
    color: '#fff',
    border: 'none'
  },
  chartsWrapper: { 
    background: '#f8f9fa', 
    borderRadius: '12px', 
    padding: '28px',
    marginBottom: '24px'
  },
  chartGrid: { 
    display: 'grid', 
    gridTemplateColumns: '1fr 1fr', 
    gap: '40px',
    marginBottom: '0'
  },
  chartColumn: { 
    display: 'flex',
    flexDirection: 'column'
  },
  miniChartTitle: { 
    fontSize: '14px', 
    fontWeight: '700', 
    color: '#1a1a2e',
    marginBottom: '16px',
    textTransform: 'uppercase',
    letterSpacing: '0.5px'
  },
  chartBars: { 
    display: 'flex', 
    gap: '12px', 
    alignItems: 'flex-end',
    justifyContent: 'space-around',
    minHeight: '160px'
  },
  barItem: { 
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    flex: '1',
    gap: '6px'
  },
  barWrapper: { 
    width: '100%',
    height: '150px',
    display: 'flex',
    alignItems: 'flex-end',
    justifyContent: 'center'
  },
  bar: { 
    width: '28px',
    borderRadius: '8px 8px 0 0',
    transition: 'all 0.3s ease',
    cursor: 'pointer',
    minHeight: '4px',
    boxShadow: '0 4px 12px rgba(0,0,0,0.1)'
  },
  barLabel: { 
    fontSize: '12px', 
    fontWeight: '600', 
    color: '#666',
    textAlign: 'center'
  },
  barValue: { 
    fontSize: '11px', 
    color: '#999',
    fontWeight: '500'
  },
  
  // Metrics Grid
  metricsGrid: { 
    display: 'grid', 
    gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', 
    gap: '16px',
    marginTop: '24px'
  },
  metricCard: { 
    padding: '18px', 
    borderRadius: '12px', 
    display: 'flex', 
    alignItems: 'center',
    gap: '12px',
    transition: 'transform 0.2s ease, box-shadow 0.2s ease'
  },
  metricIcon: { 
    fontSize: '28px',
    lineHeight: 1
  },
  metricContent: { 
    flex: 1,
    display: 'flex',
    flexDirection: 'column',
    gap: '3px'
  },
  metricTitle: { 
    fontSize: '11px',
    fontWeight: '600',
    color: '#666',
    textTransform: 'uppercase',
    letterSpacing: '0.3px'
  },
  metricValue: { 
    fontSize: '20px',
    fontWeight: '700',
    lineHeight: 1.2
  },
  metricTrend: { 
    fontSize: '10px',
    color: '#10b981',
    fontWeight: '600'
  },

  statsSection: { display: 'flex', gap: '24px', flexWrap: 'wrap', marginBottom: '24px' },
